import React, { createContext, useContext, useEffect, useState, useCallback } from "react";
import { api, saveAuth, clearAuth, getStoredUser, getToken } from "./api";

const AuthCtx = createContext(null);

export function AuthProvider({ children }) {
  const [user, setUser] = useState(getStoredUser());
  const [loading, setLoading] = useState(!!getToken());

  // `api`, `saveAuth`, `clearAuth`, `getToken`, `getStoredUser` are stable
  // module-level imports, and `setUser`/`setLoading` are stable React setters,
  // so we intentionally leave the deps array empty.
  const refresh = useCallback(async () => {
    if (!getToken()) { setUser(null); setLoading(false); return null; }
    try {
      const { data } = await api.get("/api/auth/me");
      setUser(data.user);
      saveAuth({ token: getToken(), user: data.user });
      return data.user;
    } catch (e) {
      clearAuth();
      setUser(null);
      return null;
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { refresh(); }, [refresh]);

  const login = async (email, password) => {
    const { data } = await api.post("/api/auth/login", { email, password });
    saveAuth(data);
    setUser(data.user);
    return data.user;
  };

  const signup = async (name, email, password) => {
    const { data } = await api.post("/api/auth/signup", { name, email, password });
    saveAuth(data);
    setUser(data.user);
    return data.user;
  };

  const logout = () => {
    clearAuth();
    setUser(null);
  };

  return (
    <AuthCtx.Provider value={{ user, setUser, loading, login, signup, logout, refresh }}>
      {children}
    </AuthCtx.Provider>
  );
}

export const useAuth = () => useContext(AuthCtx);
